const archiveData = $input.first().json;
let archiveText = '';

if (archiveData && archiveData.data) {
  archiveText = String(archiveData.data);
} else if (typeof archiveData === 'string') {
  archiveText = archiveData;
} else {
  archiveText = JSON.stringify(archiveData);
}

const raw = archiveText.match(/https:\/\/www\.aireport\.nl\/p\/[^\s\)"'\]]+/g) || [];
const seen = new Set();
const unique = [];
for (const u of raw) {
  const clean = u.replace(/[.,;]+$/, '');
  if (!seen.has(clean)) { seen.add(clean); unique.push(clean); }
}
// Beehiiv pins a featured article at index 0 — take index 1 for a genuinely recent post
const latestUrl = unique.length > 1 ? unique[1] : (unique[0] || null);

return [{ json: { latest_article_url: latestUrl } }];

const newsapiNode = $('Fetch NewsAPI').first();
const tldrNode = $('Fetch TLDR AI').first();
const aireportNode = $('Fetch AI Report Article').first();

let newsapiText = '[NewsAPI unavailable]';
try {
  const articles = newsapiNode.json.articles || [];
  const lines = articles.filter(a => a.title).map(a => `- [${(a.publishedAt || '').slice(0,10)}] ${a.title}: ${a.description || ''}`).slice(0, 5);
  if (lines.length > 0) newsapiText = lines.join('\n');
} catch(e) {}

let tldrText = '[TLDR AI unavailable]';
try {
  const raw = tldrNode.json;
  tldrText = String(raw.data || raw.body || JSON.stringify(raw)).substring(0, 4000);
} catch(e) {}

let aireportText = '[AI Report NL unavailable]';
try {
  const raw = aireportNode.json;
  aireportText = String(raw.data || raw.body || JSON.stringify(raw)).substring(0, 4000);
} catch(e) {}

const today = new Date().toLocaleDateString('en-GB', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric',
  timeZone: 'Europe/Berlin'
});

return [{ json: { newsapi_output: newsapiText, tldr_content: tldrText, aireport_content: aireportText, today } }];

const response = $input.first().json;
const today = $('Build Claude Payload').first().json.today;

let postText = '';
if (response.content && Array.isArray(response.content)) {
  for (const block of response.content) {
    if (block.type === 'text') postText += block.text;
  }
}

if (!postText) postText = '[Post generation failed - check Claude API response]';

const sourceList = '- NewsAPI\n- TLDR AI (tldr.tech/ai)\n- AI Report NL (aireport.nl)\n- Claude web_search';
const emailBody = 'Hi Dina,\n\nHere are your 3 LinkedIn post options for today. Pick one, copy, paste, edit if needed.\n\n' + postText + '\nSources checked today:\n' + sourceList + '\n';

return [{ json: { post_text: postText, email_body: emailBody, subject: 'Your 3 LinkedIn posts for ' + today } }];
